// Pin the head-of-queue thread and its owning container so every
// reference downstream uses syntactically identical sub-terms.
let t0: ThreadPtr = pre_self_.get_endpoint(endpoint_ptr).queue@[0];
let c0: ContainerPtr = pre_self_.get_thread(t0).owning_container;

// --- 1. Domain equalities are jointly determined by the pre-state. ---
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.thread_dom()    == pre_self_.thread_dom());
assert(post2_self_.thread_dom()    == pre_self_.thread_dom());
assert(post1_self_.endpoint_dom()  == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom()  == pre_self_.endpoint_dom());
assert(post1_self_.proc_dom()      =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom()      =~= pre_self_.proc_dom());
assert(post1_self_.proc_dom()      =~= post2_self_.proc_dom());
assert(post1_self_.page_closure()  =~= pre_self_.page_closure());
assert(post2_self_.page_closure()  =~= pre_self_.page_closure());
assert(post1_self_.page_closure()  =~= post2_self_.page_closure());

// --- 2. Per-key equalities at the "special" sites t0, c0, endpoint_ptr. ---
// Thread t0: only endpoint_descriptors is pinned (forall|t_ptr| ... fires at t0).
assert(post1_self_.get_thread(t0).endpoint_descriptors
       =~= pre_self_.get_thread(t0).endpoint_descriptors);
assert(post2_self_.get_thread(t0).endpoint_descriptors
       =~= pre_self_.get_thread(t0).endpoint_descriptors);
assert(post1_self_.get_thread(t0).endpoint_descriptors
       =~= post2_self_.get_thread(t0).endpoint_descriptors);

// Container c0: owned_procs / owned_threads / children / subtree_set unchanged.
assert(post1_self_.get_container(c0).owned_procs
       =~= pre_self_.get_container(c0).owned_procs);
assert(post2_self_.get_container(c0).owned_procs
       =~= pre_self_.get_container(c0).owned_procs);
assert(post1_self_.get_container(c0).owned_procs
       =~= post2_self_.get_container(c0).owned_procs);
assert(post1_self_.get_container(c0).owned_threads
       =~= pre_self_.get_container(c0).owned_threads);
assert(post2_self_.get_container(c0).owned_threads
       =~= pre_self_.get_container(c0).owned_threads);
assert(post1_self_.get_container(c0).owned_threads
       =~= post2_self_.get_container(c0).owned_threads);
assert(post1_self_.get_container(c0).children
       =~= pre_self_.get_container(c0).children);
assert(post2_self_.get_container(c0).children
       =~= pre_self_.get_container(c0).children);
assert(post1_self_.get_container(c0).children
       =~= post2_self_.get_container(c0).children);
assert(post1_self_.get_container(c0).subtree_set
       =~= pre_self_.get_container(c0).subtree_set);
assert(post2_self_.get_container(c0).subtree_set
       =~= pre_self_.get_container(c0).subtree_set);
assert(post1_self_.get_container(c0).subtree_set
       =~= post2_self_.get_container(c0).subtree_set);

// Endpoint endpoint_ptr: queue@ shrinks by skip(1); other fields pinned.
assert(post1_self_.get_endpoint(endpoint_ptr).queue@
       == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
assert(post2_self_.get_endpoint(endpoint_ptr).queue@
       == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
assert(post1_self_.get_endpoint(endpoint_ptr).queue@
       =~= post2_self_.get_endpoint(endpoint_ptr).queue@);
assert(post1_self_.get_endpoint(endpoint_ptr).owning_threads
       == pre_self_.get_endpoint(endpoint_ptr).owning_threads);
assert(post2_self_.get_endpoint(endpoint_ptr).owning_threads
       == pre_self_.get_endpoint(endpoint_ptr).owning_threads);
assert(post1_self_.get_endpoint(endpoint_ptr).rf_counter
       == pre_self_.get_endpoint(endpoint_ptr).rf_counter);
assert(post2_self_.get_endpoint(endpoint_ptr).rf_counter
       == pre_self_.get_endpoint(endpoint_ptr).rf_counter);
assert(post1_self_.get_endpoint(endpoint_ptr).queue_state
       == pre_self_.get_endpoint(endpoint_ptr).queue_state);
assert(post2_self_.get_endpoint(endpoint_ptr).queue_state
       == pre_self_.get_endpoint(endpoint_ptr).queue_state);
assert(post1_self_.get_endpoint(endpoint_ptr).owning_container
       =~= pre_self_.get_endpoint(endpoint_ptr).owning_container);
assert(post2_self_.get_endpoint(endpoint_ptr).owning_container
       =~= pre_self_.get_endpoint(endpoint_ptr).owning_container);

// --- 3. Pointwise equalities between post1 and post2, with explicit triggers
//     so z3 will fire the resulting universals at the same `get_*` terms it
//     sees while discharging det_schedule_blocked_thread_equal. ---

assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr)
by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr), post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != t0
    implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr)
by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
}

assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr), post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr)
    implies post1_self_.get_thread(t_ptr).endpoint_descriptors
        =~= post2_self_.get_thread(t_ptr).endpoint_descriptors
by {
    assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
           =~= post1_self_.get_thread(t_ptr).endpoint_descriptors);
    assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
           =~= post2_self_.get_thread(t_ptr).endpoint_descriptors);
}

assert forall|container_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(container_ptr), post2_self_.get_container(container_ptr)]
    pre_self_.container_dom().contains(container_ptr) && container_ptr != c0
    implies post1_self_.get_container(container_ptr)
        =~= post2_self_.get_container(container_ptr)
by {
    assert(post1_self_.get_container(container_ptr)
           =~= pre_self_.get_container(container_ptr));
    assert(post2_self_.get_container(container_ptr)
           =~= pre_self_.get_container(container_ptr));
}

assert forall|container_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(container_ptr), post2_self_.get_container(container_ptr)]
    pre_self_.container_dom().contains(container_ptr)
    implies post1_self_.get_container(container_ptr).subtree_set
        =~= post2_self_.get_container(container_ptr).subtree_set
by {
    assert(post1_self_.get_container(container_ptr).subtree_set
           =~= pre_self_.get_container(container_ptr).subtree_set);
    assert(post2_self_.get_container(container_ptr).subtree_set
           =~= pre_self_.get_container(container_ptr).subtree_set);
}

assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
    implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr)
by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
}

assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr)
    implies post1_self_.get_endpoint(e_ptr).owning_container
        =~= post2_self_.get_endpoint(e_ptr).owning_container
by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr).owning_container
           =~= post1_self_.get_endpoint(e_ptr).owning_container);
    assert(pre_self_.get_endpoint(e_ptr).owning_container
           =~= post2_self_.get_endpoint(e_ptr).owning_container);
}
